  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Looking for ways to speed up your queries, or scale easily with your serverless or edge functions?\n// Try Prisma Accelerate: https://pris.ly/cli/accelerate-init\n\n// Generate a typescypt/javascrypt client to import in Node.js\ngenerator client {\n  // Use the prisma client for JavaScript and Typescript\n  provider = \"prisma-client-js\"\n}\n\n// Connection to the database with PostgreSQL\ndatasource db {\n  // The type of the database\n  provider = \"postgresql\"\n}\n\n//enum for days of the week\nenum Day {\n  SUNDAY\n  MONDAY\n  TUESDAY\n  WEDNESDAY\n  THURSDAY\n  FRIDAY\n  SATURDAY\n  NONE\n}\n\n// Define the roles the users can have\nenum Role {\n  // Role for general users\n  USER\n  // Role to manage the website\n  ADMIN\n}\n\n// Define the status of the order\nenum OrderStatus {\n  // Order is created and being updated with items\n  CART\n  // Order is reserved and waiting for user to place the order\n  RESERVED\n  // Order is finalized and ready to be processed\n  PLACED\n  // Buyer has paid in person and the seller provided the products to the buyer\n  COMPLETED\n  // Order is cancelled by the buyer or seller\n  CANCELLED\n}\n\n// Model (data table) to store login and role information\nmodel User {\n  // Unique ID for each user\n  id           String    @id @default(cuid())\n  // Unique email address\n  email        String    @unique\n  // Hashed the passsword (Encrypt it)\n  passwordHash String\n  // List of roles for the user\n  // Set BUYER role as default\n  roles        Role[]    @default([USER])\n  // Unique profile\n  // Set to optional so that a user can exist first\n  profile      Profile?\n  // List of products that a user is selling\n  products     Product[]\n  // List of orders that a user is buying\n  orders       Order[]\n  // The date and time when a user creates an account\n  createdAt    DateTime  @default(now())\n  // The date and time when a user updates an account\n  updatedAt    DateTime  @updatedAt\n}\n\n// Model (data table) to store information about a user's profile\nmodel Profile {\n  // Unique ID for each user\n  id                 String          @id @default(cuid())\n  // Link the profile to only one user (id)\n  userId             String          @unique\n  // Reference back to the User model\n  // onDelete: Cascade means that if a user is deleted, the associated profile will also be deleted automatically\n  user               User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  // Name of the profile\n  name               String\n  // User location\n  // Set to optional since not every user will be a seller\n  location           String?\n  // Instructions for picking up orders\n  // Set to optional since not every user will be a seller\n  pickupInstructions String?         @db.Text\n  //the pickup availability schedule for each day. One array index for each day of the week\n  //All parts of DailySchedule are defaulted to false, null, etc because it won't let me make pickupTimes optional\n  pickupTimes        DailySchedule[]\n  // The date and time when a profile gets created\n  createdAt          DateTime        @default(now())\n  // The date and time when a profile gets updated\n  updatedAt          DateTime        @updatedAt\n}\n\n//data table to store a vendors available times for a specific day\nmodel DailySchedule {\n  // Unique ID for each daily schedule\n  id        String    @id @default(cuid())\n  //id of the profile the schedule is linked to\n  profileId String    @unique\n  //enum to specify which day this schedule is for. TEMPORARILY SWITCHING TO STRING TO MAKE IT EASIER\n  day       String\n  //reference back to Profile model\n  profile   Profile   @relation(fields: [profileId], references: [id], onDelete: Cascade)\n  //array to hold booleans indicated which 15 minute increments of the day are available for pickups\n  times     Boolean[] @default([false])\n  //boolean to indicate whether I store is open on a given day\n  isOpen    Boolean   @default(false)\n\n  //unique identifier so that the user doesn't have to know the id of the day they're looking for.\n  //can be found using the day and the profile id\n  @@unique(fields: [profileId, day], name: \"profileDay\")\n}\n\n// Model (data table) to store a product information\nmodel Product {\n  // Unique ID for each product\n  id          String      @id @default(cuid())\n  // Product name\n  name        String\n  // Product description\n  // @db.Text allows for longer text than the default String type\n  description String      @db.Text\n  //Product availability status\n  isAvailable Boolean     @default(false)\n  // Product reserved status\n  isReserved  Boolean     @default(false)\n  // Product price\n  price       Float\n  // Total quantity available in stock\n  stock       Int         @default(0)\n  // Reference to the seller's id\n  sellerId    String\n  // Reference back to the User model for the sellerId\n  // onDelete: Cascade means that if a user is deleted, the associated products will also be deleted automatically\n  seller      User        @relation(fields: [sellerId], references: [id], onDelete: Cascade)\n  // Reference to the orders that include this product\n  // onDelete: SetNull means that if a product is deleted, the reference in the orders will be set to null instead of deleting the orders\n  orderItems  OrderItem[]\n  // The date and time when a user creates a product\n  createdAt   DateTime    @default(now())\n  // The date and time when a user updates a product\n  updatedAt   DateTime    @updatedAt\n}\n\n// Model (data table) to store an order information\nmodel Order {\n  // Unique ID for each order\n  id        String      @id @default(cuid())\n  // Reference to the buyer's id\n  buyerId   String\n  // Reference back to the User model for the buyerId\n  // onDelete: Cascade means that if a user is deleted, the associated orders will also be deleted automatically\n  buyer     User        @relation(fields: [buyerId], references: [id], onDelete: Cascade)\n  // List of items in the order\n  items     OrderItem[]\n  // Reference to the order status\n  status    OrderStatus @default(CART)\n  // The date and time when a user creates an order\n  createdAt DateTime    @default(now())\n  // The date and time when a user updates an order\n  updatedAt DateTime    @updatedAt\n}\n\n// Model (data table) to store an order item information\nmodel OrderItem {\n  // Unique ID for each order item\n  id        String  @id @default(cuid())\n  // Reference to the order's id\n  orderId   String\n  // Reference back to the Order model for the orderId\n  // onDelete: Cascade means that if an order is deleted, the associated order items will also be deleted automatically\n  order     Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  // Reference to the product's id\n  productId String\n  // Reference back to the Product model for the productId\n  // onDelete: Cascade means that if a product is deleted, the associated order items will also be deleted automatically\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  // Quantity of the product in the order item\n  quantity  Int     @default(1)\n\n  // Prevent the same product from being added to the same order multiple times\n  // this increases the quantity instead of creating a new order item\n  @@unique([orderId, productId])\n}\n"
